import java.util.Stack;

public class ParenthesesPoem {
    public static void main(String[] args) {
        String input = "((()))"; // Example input, a poem of parentheses
        int count = 0;
        Stack<Character> stack = new Stack<>();

        for (char ch : input.toCharArray()) {
            if (ch == '(') {
                stack.push(ch);
                count++;
            } else if (ch == ')' && !stack.isEmpty()) {
                stack.pop();
                count++;
            }
        }

        System.out.println("Valid parentheses: " + count);
    }
}
```

