program EvenRowsInReverse;

const
  MAX_SIZE = 50;

var
  rows, cols: Integer;
  arr: array[1..MAX_SIZE, 1..MAX_SIZE] of Integer;
  i, j, k: Integer;

begin
  // Input: Number of rows and columns
  readln(rows, cols);

  // Input: The array itself
  for i := 1 to rows do
    for j := 1 to cols do
      read(arr[i, j]);

  // Process: Find and print even-numbered rows in reverse
  for i := rows downto 1 do
  begin
    k := 0; // Counter for even numbers in the current row
    for j := 1 to cols do
    begin
      if (arr[i, j] mod 2) = 0 then
      begin
        k := k + 1; // Count even numbers
        if k > 0 then
          write(arr[i, j], ' '); // Print even numbers, separated by space
      end;
    end;
    if k > 0 then
      writeln; // Newline after each row
  end;
end.
```

